// // This is a 4-bit counter that decrements on each clock edge and resets to zero when rst is high.
module counter4bit(clk, rst, q);
    input clk;
    input rst;
    output reg [3:0] q;

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= q + 1;
    end
endmodule
